css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: Georgia, 'Times New Roman', serif; }
body { background: #fdfcf9; color: #2a2a2a; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 26px 60px; font-family: -apple-system, BlinkMacSystemFont, sans-serif; }
.brand { font-size: 19px; font-weight: 700; font-family: Georgia, serif; }
.nav-links { display: flex; gap: 30px; }
.nav-links a { color: #999; text-decoration: none; font-size: 13.5px; font-weight: 600; }
.nav-links a.active { color: #2a2a2a; }
.hero { padding: 50px 60px 80px; max-width: 720px; }
.badge { display: inline-block; font-family: -apple-system, BlinkMacSystemFont, sans-serif; color: #b08968; font-size: 12px; font-weight: 800; letter-spacing: 0.2em; margin-bottom: 24px; }
.hero h1 { font-size: 52px; font-weight: 700; line-height: 1.3; margin-bottom: 22px; }
.hero h1 span { color: #b08968; font-style: italic; }
.hero p { color: #777; font-size: 17px; line-height: 1.9; max-width: 540px; }
.featured { padding: 0 60px 60px; }
.featured h2 { font-family: -apple-system, BlinkMacSystemFont, sans-serif; font-size: 26px; font-weight: 800; margin-bottom: 30px; }
.article-list { display: flex; flex-direction: column; }
.article-row { display: flex; gap: 24px; padding: 30px 0; border-bottom: 1px solid #ece8e0; cursor: pointer; align-items: flex-start; }
.article-row:last-child { border-bottom: none; }
.num { font-family: -apple-system, BlinkMacSystemFont, sans-serif; font-size: 28px; font-weight: 900; color: #ece8e0; flex-shrink: 0; width: 50px; }
.ainfo { flex: 1; }
.cat { display: block; font-family: -apple-system, BlinkMacSystemFont, sans-serif; color: #b08968; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.1em; margin-bottom: 6px; }
.ainfo h3 { font-size: 22px; font-weight: 700; margin-bottom: 8px; }
.ainfo p { color: #888; font-size: 14.5px; line-height: 1.7; }
.pub { font-family: -apple-system, BlinkMacSystemFont, sans-serif; font-size: 12.5px; color: #aaa; font-weight: 600; flex-shrink: 0; align-self: center; }
.books { padding: 60px; background: #f5f1e8; font-family: -apple-system, BlinkMacSystemFont, sans-serif; }
.books h2 { font-size: 26px; font-weight: 800; margin-bottom: 30px; }
.book-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 24px; max-width: 700px; }
.book-card { text-align: center; }
.book-cover { aspect-ratio: 2/3; max-width: 140px; margin: 0 auto 14px; background: white; border-radius: 6px; display: flex; align-items: center; justify-content: center; font-size: 50px; box-shadow: 0 10px 24px rgba(0,0,0,0.08); }
.book-card h3 { font-family: Georgia, serif; font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.book-card p { color: #999; font-size: 12.5px; }
.contact { text-align: center; padding: 80px 60px; font-family: -apple-system, BlinkMacSystemFont, sans-serif; }
.contact h2 { font-family: Georgia, serif; font-size: 30px; font-weight: 700; margin-bottom: 10px; }
.contact p { color: #999; font-size: 14px; margin-bottom: 26px; }
.contact button { background: #2a2a2a; color: white; border: none; padding: 15px 32px; border-radius: 4px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .navbar, .hero, .featured, .books, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 34px; } .article-row { flex-direction: column; gap: 8px; } .num { font-size: 20px; } .pub { align-self: flex-start; } }

